use std::env;
use tokio_postgres::{Client, NoTls, Error};

/// Establishes a connection to the PostgreSQL database.
///
/// The database URL must be provided via the `DATABASE_URL` environment variable.
/// Example: `DATABASE_URL=postgres://admin:password@localhost:5432/hackathon`
pub async fn connect_to_database() -> Result<Client, Box<dyn std::error::Error>> {
    let database_url = env::var("DATABASE_URL").map_err(|_| {
        "DATABASE_URL environment variable is not set. \
         Please set it before running the application, e.g.:\n  \
         export DATABASE_URL='postgres://user:password@localhost:5432/dbname'"
    })?;

    let (client, connection) = tokio_postgres::connect(&database_url, NoTls).await?;

    // Spawn the connection handler so it runs in the background
    tokio::spawn(async move {
        if let Err(e) = connection.await {
            eprintln!("Database connection error: {}", e);
        }
    });

    // Verify the connection is working
    client.simple_query("SELECT 1").await?;

    Ok(client)
}

/// Helper to load environment variables from a .env file if present (for local development).
/// Requires the `dotenvy` crate.
pub fn load_env() {
    // Silently ignore if .env file doesn't exist (e.g., in production)
    let _ = dotenvy::dotenv();
}

